namespace sv_fba0bd8a45e14198b6e6a32be1822402.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

namespace sv_fba0bd8a45e14198b6e6a32be1822402.Models;

public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime StartDate { get; set; } = DateTime.Today;
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@using sv_fba0bd8a45e14198b6e6a32be1822402.Models

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex list-unstyled justify-content-between align-items-start m-0 p-0">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepNumber = i + 1;
            var isCompleted = CompletedSteps.Contains(stepNumber);
            var isCurrent = stepNumber == CurrentStep;
            var cssClass = isCurrent ? "current" : isCompleted ? "completed" : "future";

            <li class="step @cssClass text-center flex-fill">
                @if (isCompleted && !isCurrent)
                {
                    <button type="button" class="step-circle completed-circle" @onclick="() => OnStepClicked.InvokeAsync(stepNumber)" title="Go back to @StepNames[stepNumber - 1]">
                        <span>✓</span>
                    </button>
                }
                else
                {
                    <div class="step-circle @(isCurrent ? "current-circle" : "future-circle")">
                        <span>@stepNumber</span>
                    </div>
                }
                <div class="step-label mt-1 small">@StepNames[i]</div>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-circle {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 1rem;
    border: 2px solid #dee2e6;
    background-color: #f8f9fa;
    color: #6c757d;
}

.completed-circle {
    background-color: #198754;
    border-color: #198754;
    color: white;
    cursor: pointer;
    padding: 0;
    width: 40px;
    height: 40px;
    border-radius: 50%;
    font-size: 1.1rem;
}

.completed-circle:hover {
    background-color: #157347;
    border-color: #146c43;
}

.current-circle {
    background-color: #0d6efd;
    border-color: #0d6efd;
    color: white;
}

.future-circle {
    opacity: 0.5;
}

.step.future .step-label {
    color: #adb5bd;
}

.step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

@using sv_fba0bd8a45e14198b6e6a32be1822402.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Personal Information</h5>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="Enter your full name" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" placeholder="you@example.com" />
            @if (isValidatingEmail)
            {
                <div class="form-text text-info">
                    <span class="spinner-border spinner-border-sm me-1"></span> Validating email…
                </div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>

        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <textarea class="form-control" @bind="Model.Address" @bind:event="oninput" rows="2" placeholder="Enter your address"></textarea>
        </div>

        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidatingEmail">
                Next →
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter] public PersonalInfoModel Model { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public IApplicationService? ApplicationService { get; set; }

    private string? errorMessage;
    private bool isValidatingEmail;

    private async Task HandleNext()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
        { errorMessage = "Full name is required."; return; }

        if (string.IsNullOrWhiteSpace(Model.Email))
        { errorMessage = "Email is required."; return; }

        if (string.IsNullOrWhiteSpace(Model.Phone))
        { errorMessage = "Phone number is required."; return; }

        if (string.IsNullOrWhiteSpace(Model.Address))
        { errorMessage = "Address is required."; return; }

        if (ApplicationService is not null)
        {
            isValidatingEmail = true;
            StateHasChanged();

            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            isValidatingEmail = false;

            if (!isValid)
            { errorMessage = "The email address is not valid."; return; }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_fba0bd8a45e14198b6e6a32be1822402.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Work History</h5>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            <WorkEntryEditor Entry="Entries[index]" Index="index + 1"
                             CanRemove="Entries.Count > 1"
                             OnRemove="() => RemoveEntry(index)" />
        }

        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                errorMessage = "Each position requires a company name and job title.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_fba0bd8a45e14198b6e6a32be1822402.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">References</h5>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        @for (int i = 0; i < References.Count; i++)
        {
            var index = i;
            <ReferenceEditor Reference="References[index]" Index="index + 1"
                             CanRemove="References.Count > 2"
                             OnRemove="() => RemoveReference(index)" />
        }

        @if (References.Count < 3)
        {
            <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
                + Add Reference
            </button>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "All reference fields are required.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_fba0bd8a45e14198b6e6a32be1822402.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Review & Submit</h5>
    </div>
    <div class="card-body">
        @if (IsSubmitted)
        {
            <div class="alert alert-success text-center py-4">
                <h4 class="alert-heading">Application Submitted Successfully!</h4>
                <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong></p>
                <p class="mt-2 mb-0">Thank you for applying. We'll be in touch soon.</p>
            </div>
        }
        else
        {
            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }

            <!-- Personal Info -->
            <section class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Personal Information</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
                </div>
                <dl class="row mb-0 ps-2">
                    <dt class="col-sm-3">Name</dt>
                    <dd class="col-sm-9">@Personal.FullName</dd>
                    <dt class="col-sm-3">Email</dt>
                    <dd class="col-sm-9">@Personal.Email</dd>
                    <dt class="col-sm-3">Phone</dt>
                    <dd class="col-sm-9">@Personal.Phone</dd>
                    <dt class="col-sm-3">Address</dt>
                    <dd class="col-sm-9">@Personal.Address</dd>
                </dl>
                <hr />
            </section>

            <!-- Work History -->
            <section class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Work History</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
                </div>
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 ps-3 border-start border-2">
                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                        <small class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 mt-1">@entry.Description</p>
                        }
                    </div>
                }
                <hr />
            </section>

            <!-- References -->
            <section class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">References</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
                </div>
                @foreach (var r in References)
                {
                    <div class="mb-2 ps-3 border-start border-2">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <small class="text-muted">@r.Email | @r.Phone</small>
                    </div>
                }
                <hr />
            </section>

            <!-- Cover Letter -->
            <section class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Cover Letter</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
                </div>
                <div class="ps-3 border-start border-2" style="white-space: pre-wrap;">@CoverLetter</div>
            </section>

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
                <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                    @if (IsSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        <text>Submitting…</text>
                    }
                    else
                    {
                        <text>Submit Application</text>
                    }
                </button>
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public PersonalInfoModel Personal { get; set; } = new();
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }

    private string? errorMessage;

    private async Task HandleSubmit()
    {
        errorMessage = null;
        await OnSubmit.InvokeAsync();
    }
}

@page "/apply"
@using sv_fba0bd8a45e14198b6e6a32be1822402.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="() => CompleteAndAdvance(1)" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="() => CompleteAndAdvance(2)"
                             OnBack="() => GoToStep(1)" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnNext="() => CompleteAndAdvance(3)"
                            OnBack="() => GoToStep(2)" />
            break;
        case 4:
            <CoverLetterStep CoverLetter="@coverLetter"
                             CoverLetterChanged="val => coverLetter = val"
                             OnNext="() => CompleteAndAdvance(4)"
                             OnBack="() => GoToStep(3)" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        IsSubmitting="isSubmitting"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        OnEdit="GoToStep"
                        OnBack="() => GoToStep(4)"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private bool isSubmitting;
    private bool isSubmitted;
    private int? applicationId;

    private void GoToStep(int step)
    {
        if (step < currentStep || completedSteps.Contains(step))
            currentStep = step;
    }

    private void CompleteAndAdvance(int step)
    {
        completedSteps.Add(step);
        currentStep = step + 1;
    }

    private async Task SubmitApplication()
    {
        isSubmitting = true;

        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
            completedSteps.Add(5);
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

namespace sv_fba0bd8a45e14198b6e6a32be1822402.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
