{"path": "/tmp/sv-fba0bd8a45e14198b6e6a32be1822402/Components/Pages/JobApplication/ReviewStep.razor", "file_text": "@using sv_fba0bd8a45e14198b6e6a32be1822402.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Review & Submit</h5>
    </div>
    <div class="card-body">
        @if (IsSubmitted)
        {
            <div class="alert alert-success text-center py-4">
                <h4 class="alert-heading">Application Submitted Successfully!</h4>
                <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong></p>
                <p class="mt-2 mb-0">Thank you for applying. We'll be in touch soon.</p>
            </div>
        }
        else
        {
            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }

            <!-- Personal Info -->
            <section class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Personal Information</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
                </div>
                <dl class="row mb-0 ps-2">
                    <dt class="col-sm-3">Name</dt>
                    <dd class="col-sm-9">@Personal.FullName</dd>
                    <dt class="col-sm-3">Email</dt>
                    <dd class="col-sm-9">@Personal.Email</dd>
                    <dt class="col-sm-3">Phone</dt>
                    <dd class="col-sm-9">@Personal.Phone</dd>
                    <dt class="col-sm-3">Address</dt>
                    <dd class="col-sm-9">@Personal.Address</dd>
                </dl>
                <hr />
            </section>

            <!-- Work History -->
            <section class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Work History</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
                </div>
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-2 ps-3 border-start border-2">
                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                        <small class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mb-0 mt-1">@entry.Description</p>
                        }
                    </div>
                }
                <hr />
            </section>

            <!-- References -->
            <section class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">References</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
                </div>
                @foreach (var r in References)
                {
                    <div class="mb-2 ps-3 border-start border-2">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <small class="text-muted">@r.Email | @r.Phone</small>
                    </div>
                }
                <hr />
            </section>

            <!-- Cover Letter -->
            <section class="mb-4">
                <div class="d-flex justify-content-between align-items-center">
                    <h6 class="fw-bold">Cover Letter</h6>
                    <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(4)">Edit</button>
                </div>
                <div class="ps-3 border-start border-2" style="white-space: pre-wrap;">@CoverLetter</div>
            </section>

            <div class="d-flex justify-content-between">
                <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
                <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                    @if (IsSubmitting)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                        <text>Submitting…</text>
                    }
                    else
                    {
                        <text>Submit Application</text>
                    }
                </button>
            </div>
        }
    </div>
