    color: white;
}

.future-circle {
    opacity: 0.5;
}

.step.future .step-label {
    color: #adb5bd;
}

.step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

