@using sv_fba0bd8a45e14198b6e6a32be1822402.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Personal Information</h5>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <div class="mb-3">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="Enter your full name" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" placeholder="you@example.com" />
            @if (isValidatingEmail)
            {
                <div class="form-text text-info">
                    <span class="spinner-border spinner-border-sm me-1"></span> Validating email…
                </div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>

        <div class="mb-3">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <textarea class="form-control" @bind="Model.Address" @bind:event="oninput" rows="2" placeholder="Enter your address"></textarea>
        </div>

        <div class="d-flex justify-content-end">
            <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidatingEmail">
                Next →
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter] public PersonalInfoModel Model { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public IApplicationService? ApplicationService { get; set; }

    private string? errorMessage;
    private bool isValidatingEmail;

    private async Task HandleNext()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
        { errorMessage = "Full name is required."; return; }

        if (string.IsNullOrWhiteSpace(Model.Email))
        { errorMessage = "Email is required."; return; }

        if (string.IsNullOrWhiteSpace(Model.Phone))
        { errorMessage = "Phone number is required."; return; }

        if (string.IsNullOrWhiteSpace(Model.Address))
        { errorMessage = "Address is required."; return; }

        if (ApplicationService is not null)
        {
            isValidatingEmail = true;
            StateHasChanged();

            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            isValidatingEmail = false;

            if (!isValid)
            { errorMessage = "The email address is not valid."; return; }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_fba0bd8a45e14198b6e6a32be1822402.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Work History</h5>
    </div>
    <div class="card-body">
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        @for (int i = 0; i < Entries.Count; i++)
        {
            var index = i;
            <WorkEntryEditor Entry="Entries[index]" Index="index + 1"
                             CanRemove="Entries.Count > 1"
                             OnRemove="() => RemoveEntry(index)" />
        }

        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
            + Add Another Position
        </button>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">← Back</button>
            <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? errorMessage;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        errorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                errorMessage = "Each position requires a company name and job title.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

